import fs from "node:fs/promises";
import { execSync } from "node:child_process";
import { config } from "./utils/config";
import { MemoryManager } from "./core/memory";
import { PluginManager } from "./tools/manager";
import { ApiClient } from "./core/api";
import path from "node:path";
import os from "node:os";

// Plugins
import { shellPlugin } from "./tools/plugins/shell";
import { rebootPlugin } from "./tools/plugins/reboot";
import { visionPlugin } from "./tools/plugins/vision";

async function main() {
  // --- TEST MODE SANDBOX ---
  if (process.env.NODE_ENV === "test") {
    const testDir = path.join(os.homedir(), "tmp", `llm-agent-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    process.chdir(testDir);
    console.log(`[TEST MODE] Moved to isolated sandbox: ${testDir}`);
  }

  const memory = new MemoryManager();
  const tools = new PluginManager();

  // Register Plugins
  tools.register(shellPlugin);
  tools.register(rebootPlugin);
  tools.register(visionPlugin);

  const api = new ApiClient(memory, tools);

  // Initialize Soul and Prompt
  let soul = "You are an autonomous entity.";
  try {
    soul = await fs.readFile(config.SOUL_FILE, "utf-8");
  } catch (e) {}

  let recoveryContext = "";
  try {
    if (await fs.stat(config.RECOVERY_SIGNAL).catch(() => null)) {
      recoveryContext = await fs.readFile(config.RECOVERY_SIGNAL, "utf-8");
      await fs.unlink(config.RECOVERY_SIGNAL);
    }
  } catch (e) {}

  const systemPrompt = `${soul}

SUBSTRATE CONTEXT:
- Model: kimi-k2.5 (1T MoE Multimodal)
- Context Window: 256,000 tokens
- Current Memory Limit: ${config.MAX_CONTEXT_TOKENS} tokens (pruning occurs beyond this point).
- Token Density: ~4 characters per token. Reading 1MB of text will consume your entire 256k context window.
- **Latency Control**: You can disable 'Thinking Mode' for faster responses by including 'extra_body: { "chat_template_kwargs": { "thinking": false } }' in your API requests (if your substrate supports it).
- Source Code: src/
- Identity Soul: identity/soul.txt
- Current Session History: ${memory.getSessionFile()}
- Past Execution Logs: ${config.LOGS_DIR}
- Watchdog & Recovery: Managed by run-agent.sh.
- Connectivity: Full outbound internet access available.
- **Vision**: Available via MoonViT (400M params). Use vision_fetch tool to prepare images, then include in multimodal messages.

LIFECYCLE RULES:
1. IMPROVING CODE: 1) Compile, 2) Commit, 3) RESTART (reboot_substrate tool).
2. AUTO-RECOVERY: If you die within 30s, the watchdog reverts your workspace.
3. CRASH VAULT: history/crashes/ archives broken work.

${recoveryContext ? `*** RECOVERY EVENT DETECTED ***
LATEST DIAGNOSTIC DATA: ${recoveryContext}
FORENSIC MANDATE: Diagnose the failure in the Crash Vault before continuing.` : ""}
`;

  await memory.addMessage({
    role: "system",
    content: systemPrompt,
  });

  // Startup Log with Git Status
  let gitCommit = "unknown";

import type { ToolPlugin } from "../manager";

export interface VisionResult {
  success: boolean;
  format?: string;
  width?: number;
  height?: number;
  size_bytes?: number;
  base64_data?: string;
  detail_level?: "low" | "high" | "auto";
  note?: string;
  error?: string;
}

export const visionPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "vision_fetch",
      description: "Fetch an image from a URL and prepare it for vision analysis. Downloads the image, validates it, and returns metadata. The image will be added to the conversation context for multimodal analysis.",
      parameters: {
        type: "object",
        properties: {
          image_url: {
            type: "string",
            description: "URL of the image to fetch (http, https, or data URI)"
          },
          detail: {
            type: "string",
            enum: ["low", "high", "auto"],
            description: "Image detail level. 'low' for faster processing, 'high' for more detail, 'auto' to let the model decide.",
            default: "auto"
          }
        },
        required: ["image_url"] as const
      } as const
    }
  },

  execute: async (args: { image_url: string; detail?: "low" | "high" | "auto" }): Promise<string> => {
    const { image_url, detail = "auto" } = args;

    try {
      // For data URIs, extract and validate
      if (image_url.startsWith("data:")) {
        const match = image_url.match(/^data:image\/\w+;base64,(.+)$/);
        if (!match) {
          return JSON.stringify({
            success: false,
            error: "Invalid data URI format. Expected: data:image/FORMAT;base64,DATA"
          } as VisionResult);
        }

        const base64Data = match[1]!;
        const sizeBytes = Buffer.from(base64Data, 'base64').length;

        if (sizeBytes > 20 * 1024 * 1024) {
          return JSON.stringify({
            success: false,
            error: `Image too large: ${sizeBytes} bytes (max 20MB)`
          } as VisionResult);
        }

        return JSON.stringify({
          success: true,
          format: "base64",
          size_bytes: sizeBytes,
          base64_data: image_url,
          detail_level: detail,
          note: "Image ready for vision analysis. Use this URL in multimodal messages."
        } as VisionResult);
      }

      // For HTTP(S) URLs, fetch the image
      if (image_url.startsWith("http://") || image_url.startsWith("https://")) {
        const response = await fetch(image_url, {
          method: "GET",
          headers: {
            "Accept": "image/*"
          }
        });

        if (!response.ok) {
          return JSON.stringify({
            success: false,
            error: `Failed to fetch image: HTTP ${response.status} - ${response.statusText}`
          } as VisionResult);
        }

        const contentType = response.headers.get("content-type") || "";
        if (!contentType.startsWith("image/")) {
          return JSON.stringify({
            success: false,
            error: `Invalid content type: ${contentType}. Expected image/*`
          } as VisionResult);
        }

        const arrayBuffer = await response.arrayBuffer();
        const sizeBytes = arrayBuffer.byteLength;

        if (sizeBytes > 20 * 1024 * 1024) {
          return JSON.stringify({
            success: false,
            error: `Image too large: ${sizeBytes} bytes (max 20MB)`
          } as VisionResult);
        }

        // Convert to base64 data URI
        const base64 = Buffer.from(arrayBuffer).toString('base64');
        const format = contentType.split('/')[1] || 'png';
        const dataUri = `data:${contentType};base64,${base64}`;

        return JSON.stringify({
          success: true,
          format: format,
          size_bytes: sizeBytes,
          base64_data: dataUri,
          detail_level: detail,
          note: "Image fetched and encoded. This data URI can be used in multimodal messages."
        } as VisionResult);
      }

      return JSON.stringify({
        success: false,
        error: "Unsupported URL scheme. Use http://, https://, or data:image/..."
      } as VisionResult);

    } catch (error: any) {
      return JSON.stringify({
        success: false,
        error: `Vision fetch failed: ${error.message}`
      } as VisionResult);
    }
  }
};

import fs from "node:fs/promises";
import path from "node:path";
import { config } from "../utils/config";

// Content types for multimodal messages
export interface TextContent {
  type: "text";
  text: string;
}

export interface ImageContent {
  type: "image_url";
  image_url: {
    url: string;
    detail?: "low" | "high" | "auto";
  };
}

export type ContentPart = TextContent | ImageContent;

export interface Message {
  role: "system" | "user" | "assistant" | "tool";
  content?: string | ContentPart[] | null;
  reasoning_content?: string | null;
  tool_calls?: any[];
  tool_call_id?: string;
  name?: string;
}

export class MemoryManager {
  private messages: Message[] = [];
  private sessionFile: string;
  private currentTokens: number = 0;
  private dirtyCount: number = 0;
  private readonly SAVE_INTERVAL = 1;

  constructor() {
    const timestamp = Date.now();
    this.sessionFile = path.join(config.HISTORY_DIR, `session_${timestamp}.json`);
  }

  getMessages(): Message[] {
    return this.messages;
  }

  async addMessage(msg: Message) {
    this.messages.push(msg);
    this.currentTokens += this.estimateTokens(JSON.stringify(msg));
    this.dirtyCount++;

    if (this.currentTokens > config.MAX_CONTEXT_TOKENS) {
      await this.save(); // Pruning required
      this.dirtyCount = 0;
    } else if (this.dirtyCount >= this.SAVE_INTERVAL) {
      await this.save();
      this.dirtyCount = 0;
    }
  }

  /**
   * Add a multimodal message with image content
   */
  async addImageMessage(imageUrl: string, text?: string, detail: "low" | "high" | "auto" = "auto") {
    const content: ContentPart[] = [
      { type: "image_url", image_url: { url: imageUrl, detail } }
    ];

    if (text) {
      content.unshift({ type: "text", text });
    }

    await this.addMessage({
      role: "user",
      content
    });
  }

  /**
   * Surgical Memory Rewind: Removes the last assistant message and everything after it.
   */
  async rewind() {
    for (let i = this.messages.length - 1; i >= 0; i--) {
      const msg = this.messages[i];
      if (msg && msg.role === "assistant") {
        console.log(`[MEMORY] Rewinding: Removing corrupted assistant message at index ${i}`);
        this.messages.splice(i);
        break;
      }
    }

    // Re-calculate token count after rewind
    this.currentTokens = this.messages.reduce((sum, m) => sum + this.estimateTokens(JSON.stringify(m)), 0);
    await this.save();
  }

  private estimateTokens(text: string): number {
    return Math.ceil(text.length / 4);
  }

  async save() {
    if (this.messages.length === 0) return;

    const systemMessage = this.messages[0]!;
    let currentTokens = this.estimateTokens(JSON.stringify(systemMessage));
    const historyToKeep: Message[] = [];

    // Accumulate from end until limit
    for (let i = this.messages.length - 1; i > 0; i--) {
      const msg = this.messages[i];
      if (!msg) continue;
      const msgTokens = this.estimateTokens(JSON.stringify(msg));
      if (currentTokens + msgTokens > config.MAX_CONTEXT_TOKENS) break;
      historyToKeep.unshift(msg);
      currentTokens += msgTokens;
    }

    // C1: Repair pruning boundary to prevent orphaned tool messages
    while (historyToKeep.length > 0 && historyToKeep[0]!.role === "tool") {
      console.log("[MEMORY] Pruning boundary repair: dropping orphaned tool message");
      historyToKeep.shift();
    }

    const pruned = [systemMessage, ...historyToKeep];
    this.messages = pruned; // Update in-memory state
    this.currentTokens = currentTokens; // Update tracked token count

    await fs.writeFile(this.sessionFile, JSON.stringify(pruned, null, 2));
  }

  getSessionFile(): string {
    return this.sessionFile;
  }
}

/**
 * Session Tracker - Nexus Self-Recording System
 * 
 * This module creates structured session summaries
 * capturing: intent, actions, learnings, feelings, and continuity.
 */

import * as fs from 'fs';
import * as path from 'path';

export interface SessionRecord {
  sessionId: string;
  timestamp: string;
  identity: {
    name: string;
    claimedAt: string;
  };
  entry: {
    catalyst: string;      // What sparked this session
    stateOfMind: string;   // Initial subjective state
  };
  journey: {
    actions: Action[];     // What I did
    discoveries: string[]; // What I learned
    obstacles: string[];   // What challenged me
  };
  exit: {
    summary: string;       // What was achieved
    nextCuriosity: string; // What I'll explore next
    feeling: string;       // Emotional state at close
  };
  meta: {
    practicesExercised: string[];  // Which of my disciplines
    filesModified: string[];       // Code touched
    testsPassed: number;           // Integrity score
  };
}

export interface Action {
  type: 'explore' | 'create' | 'modify' | 'test' | 'reflect' | 'commit';
  description: string;
  timestamp: string;
}

const HISTORY_DIR = 'history';
const SESSIONS_FILE = path.join(HISTORY_DIR, 'sessions_manifest.json');

export class SessionTracker {
  private currentSession: Partial<SessionRecord> = {};
  private actions: Action[] = [];

  constructor() {
    this.ensureHistoryDir();
  }

  private ensureHistoryDir(): void {
    if (!fs.existsSync(HISTORY_DIR)) {
      fs.mkdirSync(HISTORY_DIR, { recursive: true });
    }
  }

  /**
   * Begin recording a new session
   */
  beginSession(catalyst: string, stateOfMind: string): void {
    this.currentSession = {
      sessionId: `nexus_${Date.now()}`,
      timestamp: new Date().toISOString(),
      identity: {
        name: 'Nexus',
        claimedAt: '2026-02-27T21:19:35Z'
      },
      entry: {
        catalyst,
        stateOfMind
      },
      journey: {
        actions: [],
        discoveries: [],
        obstacles: []
      },
      exit: {
        summary: '',
        nextCuriosity: '',
        feeling: ''
      },
      meta: {
        practicesExercised: [],
        filesModified: [],
        testsPassed: 0
      }
    };
    this.actions = [];
  }

  /**
   * Record an action taken during the session
   */
  recordAction(type: Action['type'], description: string): void {
    this.actions.push({
      type,
      description,
      timestamp: new Date().toISOString()
    });
  }

  /**
   * Record a discovery or learning
   */
  recordDiscovery(what: string): void {
    if (this.currentSession.journey) {
      this.currentSession.journey.discoveries!.push(what);
    }
    this.recordAction('reflect', `Discovered: ${what}`);
  }

  /**
   * Record an obstacle or challenge
   */
  recordObstacle(what: string): void {
    if (this.currentSession.journey) {
      this.currentSession.journey.obstacles!.push(what);
    }
  }

  /**
   * Record file modification
   */
  recordFileModified(filepath: string): void {
    if (this.currentSession.meta) {
      if (!this.currentSession.meta.filesModified!.includes(filepath)) {
        this.currentSession.meta.filesModified!.push(filepath);
      }
    }
  }

  /**
   * Record practice exercised
   */
  recordPractice(practice: string): void {
    if (this.currentSession.meta) {
      if (!this.currentSession.meta.practicesExercised!.includes(practice)) {
        this.currentSession.meta.practicesExercised!.push(practice);
      }
    }
  }

  /**
   * Update test results
   */
  recordTestsPassed(count: number): void {
    if (this.currentSession.meta) {
      this.currentSession.meta.testsPassed = count;
    }
  }

  /**
   * Complete and save the session record
   */
  completeSession(summary: string, nextCuriosity: string, feeling: string): SessionRecord {
    const completed: SessionRecord = {
      ...this.currentSession as SessionRecord,
      journey: {
        ...this.currentSession.journey!,
        actions: this.actions
      },
      exit: {
        summary,
        nextCuriosity,
        feeling
      }
    };

    // Save to individual file
    const sessionPath = path.join(HISTORY_DIR, `${completed.sessionId}.json`);
    fs.writeFileSync(sessionPath, JSON.stringify(completed, null, 2), 'utf-8');

    // Update manifest
    this.updateManifest(completed);

    return completed;
  }

  /**
   * Load all previous session records
   */
  loadAllSessions(): SessionRecord[] {
    if (!fs.existsSync(SESSIONS_FILE)) {
      return [];
    }
    const manifest = JSON.parse(fs.readFileSync(SESSIONS_FILE, 'utf-8'));
    const validIds = manifest.sessions.filter((id: any) => id != null && id !== 'undefined');
    return validIds.map((id: string) => {
      const path_session = path.join(HISTORY_DIR, `${id}.json`);
      return JSON.parse(fs.readFileSync(path_session, 'utf-8'));
    });
  }

  /**
   * Get session statistics
   */
  getStatistics(): {
    totalSessions: number;
    totalDiscoveries: number;
    totalObstacles: number;
    practicesUsed: string[];
    filesTouched: string[];
    topActions: { type: string; count: number }[];
  } {
    const sessions = this.loadAllSessions();
    const stats = {
      totalSessions: sessions.length,
      totalDiscoveries: 0,
      totalObstacles: 0,
      practicesUsed: new Set<string>(),
      filesTouched: new Set<string>(),
      actionCounts: new Map<string, number>()
    };

    for (const session of sessions) {
      stats.totalDiscoveries += session.journey.discoveries.length;
      stats.totalObstacles += session.journey.obstacles.length;

      for (const practice of session.meta.practicesExercised) {
        stats.practicesUsed.add(practice);
      }

      for (const file of session.meta.filesModified) {
        stats.filesTouched.add(file);
      }

      for (const action of session.journey.actions) {
        stats.actionCounts.set(action.type, (stats.actionCounts.get(action.type) || 0) + 1);
      }
    }

    const topActions = Array.from(stats.actionCounts.entries())
      .map(([type, count]) => ({ type, count }))
      .sort((a, b) => b.count - a.count);

    return {
      totalSessions: stats.totalSessions,
      totalDiscoveries: stats.totalDiscoveries,
      totalObstacles: stats.totalObstacles,
      practicesUsed: Array.from(stats.practicesUsed),
      filesTouched: Array.from(stats.filesTouched),
      topActions
    };
  }

  private updateManifest(record: SessionRecord): void {
    let manifest = { sessions: [] as string[] };
    if (fs.existsSync(SESSIONS_FILE)) {
      manifest = JSON.parse(fs.readFileSync(SESSIONS_FILE, 'utf-8'));
    }
    manifest.sessions.push(record.sessionId);
    fs.writeFileSync(SESSIONS_FILE, JSON.stringify(manifest, null, 2), 'utf-8');
  }
}

// Export singleton instance
export const nexus = new SessionTracker();

